package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import org.joda.time.LocalDate;

import java.util.Collection;
import java.util.List;
import java.util.Map;
import java.util.Map.Entry;
import java.util.Set;

public final class SocialeBijdragenDmfapplVrijwilligeBrandweer {
    private static final int LOONCODE_REGELMATIGE_PRESTATIES_LAAG = 542;
    private static final int LOONCODE_REGELMATIGE_PRESTATIES_HOOG = 942;
    private static final int LOONCODE_REGELMATIGE_PRESTATIES_FICTIEF_CODE = 1942;
    private static final int LOONCODE_REGELMATIGE_PRESTATIES_FICTIEF_EXT = 998;

    private SocialeBijdragenDmfapplVrijwilligeBrandweer() {
    }

    public static boolean isOpdrachtVrijwilligeBrandweer(RekenTijd rekenTijd, Opdracht opdracht) {
        boolean test = false;
        for (Opper opper : opdracht.getOpperSlices()) {
            Rszppo rszppo = opper.getRszppo();
            test = WerknemersKengetalFactory.isVrijwilligeBrandweer(rekenTijd, rszppo.getWerknemersKengetal(), rszppo.getStatuutDmfappl());
            if (test) {
                break;
            }
        }
        return test;
    }

    public static Money getBasis(
            RekenTijd rekenTijd, LoonElementManager manager, List<RekenHoofd> kwartaalResultaten, Set<OpdrachtDatumLoonCodeKey> voorkomenCode,
            Map<Integer, Opdracht> opdrachtMap) {
        Money basis = analyseerKwartaalResultaten(rekenTijd, kwartaalResultaten, voorkomenCode, rekenTijd.beginDatum, opdrachtMap);
        return basis.add(analyseerHuidigeMaand(rekenTijd, manager, voorkomenCode, rekenTijd.beginDatum));
    }

    public static Money analyseerKwartaalResultaten(
            RekenTijd rekenTijd, List<RekenHoofd> kwartaalResultaten, Set<OpdrachtDatumLoonCodeKey> voorkomenCode, LocalDate huidigeBeginDatum,
            Map<Integer, Opdracht> opdrachtMap) {
        Money basis = Money.ZERO;
        MoneyMap<OpdrachtDatumLoonCodeKey> voorkomenCodeMap = new HashMoneyMap<>();
        for (RekenHoofd hoofd : kwartaalResultaten) {
            basis = basis.add(analyseerKwartaalResultatenRekenhoofd(rekenTijd, huidigeBeginDatum, voorkomenCodeMap, hoofd, opdrachtMap));
        }
        for (Entry<OpdrachtDatumLoonCodeKey, Money> entry : voorkomenCodeMap.entrySet()) {
            if (entry.getValue().signum() != 0) {
                voorkomenCode.add(entry.getKey());
            }
        }
        return basis;
    }

    private static Money analyseerKwartaalResultatenRekenhoofd(
            RekenTijd rekenTijd, LocalDate huidigeBeginDatum, MoneyMap<OpdrachtDatumLoonCodeKey> voorkomenCodeMap, RekenHoofd hoofd,
            Map<Integer, Opdracht> opdrachtMap) {

        Money basis = Money.ZERO;
        Opdracht opdracht = opdrachtMap.get(hoofd.getOpdracht().getId());
        if (opdracht != null) {
            Opper opperLaatsteGegevens = RekenTools.getOpperLaatsteGegevens(opdracht);
            Rszppo rszppo = opperLaatsteGegevens.getRszppo();
            if (!hoofd.getBeginDatum().equals(huidigeBeginDatum) &&
                    WerknemersKengetalFactory.isVrijwilligeBrandweer(rekenTijd, hoofd.getWerknemersKengetal(), rszppo.getStatuutDmfappl())) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    basis = basis.add(analyseerKwartaalResultatenRekenlijn(hoofd, lijn, voorkomenCodeMap));
                }
            }
        }
        return basis;
    }

    private static Money analyseerKwartaalResultatenRekenlijn(
            RekenHoofd hoofd, RekenLijn lijn, MoneyMap<OpdrachtDatumLoonCodeKey> voorkomenCodeMap) {
        Money basis = Money.ZERO;
        AardKodeExtensie looncode = lijn.getAardKodeExtensie();
        if (isRegelmatigePrestatie(looncode) || isFictief(looncode)) {
            for (RekenBedrag bedrag : lijn.getRekenBedragen()) {
                basis = basis.add(analyseerKwartaalResultatenRekenBedrag(hoofd, lijn, looncode, bedrag, voorkomenCodeMap));
            }
        }
        return basis;
    }

    private static Money analyseerKwartaalResultatenRekenBedrag(
            RekenHoofd hoofd, RekenLijn lijn, AardKodeExtensie looncode, RekenBedrag rekenBedrag, MoneyMap<OpdrachtDatumLoonCodeKey> voorkomenCodeMap) {
        Money basis = Money.ZERO;
        RekenBedragType bedragType = rekenBedrag.getBedragType();
        LocalDate beginDatum = hoofd.getBeginDatum();
        MoneyKey moneyKey = RekenTools.bedragTypeToMoneyKey(bedragType, lijn.getRegimeBv(), beginDatum);
        if (moneyKey == RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY) {
            basis = basis.add(rekenBedrag.getBedrag());
        } else {
            if (bedragType == RekenBedragType.BRUTO_MAANDLOON) {
                OpdrachtDatumLoonCodeKey opdrachtDatumLoonCodeKey = new OpdrachtDatumLoonCodeKey(hoofd.getOpdracht(), beginDatum, looncode);
                voorkomenCodeMap.addToMoney(opdrachtDatumLoonCodeKey, rekenBedrag.getBedrag());
            }
        }
        return basis;
    }

    public static Money analyseerHuidigeMaand(
            RekenTijd rekenTijd, LoonElementManager manager, Set<OpdrachtDatumLoonCodeKey> voorkomenCode, LocalDate beginDatum) {
        Money basis = Money.ZERO;
        Collection<LoonElement> loonElementen = manager.getPersoonsElementen();
        for (LoonElement element : loonElementen) {
            basis = basis.add(analyseerHuidigeMaandLoonElement(rekenTijd, voorkomenCode, beginDatum, element));
        }
        return basis;
    }

    private static Money analyseerHuidigeMaandLoonElement(
            RekenTijd rekenTijd, Set<OpdrachtDatumLoonCodeKey> voorkomenCode, LocalDate beginDatum, LoonElement element) {
        Opper opper = element.getOpper();
        Rszppo rszppo = opper.getRszppo();
        Money basis = Money.ZERO;
        if (WerknemersKengetalFactory.isVrijwilligeBrandweer(rekenTijd, rszppo.getWerknemersKengetal(), rszppo.getStatuutDmfappl())) {
            AardKodeExtensie looncode = element.getAardKodeExtensie();
            if (isRegelmatigePrestatie(looncode)) {
                basis = basis.add(element.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY));
                voorkomenCode.add(new OpdrachtDatumLoonCodeKey(opper.getOpdracht(), beginDatum, looncode));
            } else {
                if (isFictief(looncode)) {
                    basis = basis.add(element.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY));
                }
            }
        }
        return basis;
    }

    private static boolean isFictief(AardKodeExtensie looncode) {
        return looncode.getCode() == LOONCODE_REGELMATIGE_PRESTATIES_FICTIEF_CODE && looncode.getExtensie() == LOONCODE_REGELMATIGE_PRESTATIES_FICTIEF_EXT;
    }

    public static int getFouteCode(Money grens, Money basis) {
        return basis.compareTo(grens) <= 0 ? LOONCODE_REGELMATIGE_PRESTATIES_HOOG : LOONCODE_REGELMATIGE_PRESTATIES_LAAG;
    }

    private static boolean isRegelmatigePrestatie(AardKodeExtensie looncode) {
        Integer code = looncode.getCode();
        return code == LOONCODE_REGELMATIGE_PRESTATIES_LAAG || code == LOONCODE_REGELMATIGE_PRESTATIES_HOOG;
    }
}
